1	import {
2	  type CSSProperties,
3	  type JSX,
4	  type KeyboardEvent,
5	  type ReactNode,
6	  useCallback,
7	  useId,
8	  useState,
9	} from 'react';
10	import { useTranslation } from 'react-i18next';
11	import { Icons, ICON_SIZE } from '@bim-ai/ui';
12	import type { LensMode } from '@bim-ai/core';
13	import type { CollaborationConflictQueueV1 } from '../lib/collaborationConflictQueue';
14	import { LensDropdown } from './LensDropdown';
15	import { DriftBadge } from './DriftBadge';
16	
17	/**
18	 * StatusBar — spec §17.
19	 *
20	 * 28 px tall surface bar, bottom-of-shell. Shows clusters from left to
21	 * right: active level, current tool, snap mode group, grid toggle, model
22	 * coordinates, undo depth, ws connection, save state.
23	 *
24	 * - Coordinates use `aria-live="polite"` so screen-readers can announce
25	 *   changes without interrupting.
26	 * - The save-state pill uses `aria-live="polite"` too.
27	 * - Errors / red-alert states (offline, save failed) use
28	 *   `aria-live="assertive"`.
29	 * - Every cluster has a tooltip via `title` and a hotkey hint where the
30	 *   spec specifies one (`F3` for snap cycle, `F7` for grid).
31	 */
32	
33	export type StatusSaveState = 'saved' | 'saving' | 'unsynced' | 'error';
34	export type StatusWsState = 'connected' | 'reconnecting' | 'offline';
35	
36	export interface StatusBarProps {
37	  level: { id: string; label: string };
38	  levels?: { id: string; label: string }[];
39	  onLevelChange?: (id: string) => void;
40	  toolLabel?: string | null;
41	  /** Snap mode group; toggling individual snaps lives here. */
42	  snapModes?: { id: string; label: string; on: boolean }[];
43	  onSnapToggle?: (id: string) => void;
44	  gridOn?: boolean;
45	  onGridToggle?: () => void;
46	  /** Live cursor model coords, in mm; null when off-canvas. */
47	  cursorMm?: { xMm: number; yMm: number } | null;
48	  /** Undo depth; clicking the cluster invokes undo / redo. */
49	  undoDepth?: number;
50	  onUndo?: () => void;
51	  onRedo?: () => void;
52	  wsState?: StatusWsState;
53	  saveState?: StatusSaveState;
54	  conflictQueue?: CollaborationConflictQueueV1 | null;
55	  onClearConflict?: () => void;
56	  /** CHR-V3-03 slot 5 — lens discipline filter. */
57	  lensMode?: LensMode;
58	  onLensChange?: (lens: LensMode) => void;
59	  /** CHR-V3-03 slot 6 — federation drift count; hidden when 0. */
60	  driftCount?: number;
61	  onDriftClick?: () => void;
62	  /** CHR-V3-05 slot 7 — activity-stream entry. */
63	  activityUnreadCount?: number;
64	  onActivityClick?: () => void;
65	}
66	
67	export function StatusBar({
68	  level,
69	  levels = [],
70	  onLevelChange,
71	  toolLabel,
72	  snapModes = [],
73	  onSnapToggle,
74	  gridOn = true,
75	  onGridToggle,
76	  cursorMm,
77	  undoDepth,
78	  onUndo,
79	  onRedo,
80	  wsState = 'connected',
81	  saveState = 'saved',
82	  conflictQueue,
83	  onClearConflict,
84	  lensMode = 'all',
85	  onLensChange,
86	  driftCount = 0,
87	  onDriftClick,
88	  activityUnreadCount = 0,
89	  onActivityClick,
90	}: StatusBarProps): JSX.Element {
91	  return (
92	    <div
93	      data-testid="status-bar"
94	      role="contentinfo"
95	      style={statusStyle}
96	      className="relative flex w-full items-center gap-3 border-t border-border bg-surface px-4 text-xs"
97	    >
98	      <LevelCluster level={level} levels={levels} onLevelChange={onLevelChange} />
99	      <Divider />
100	      <ToolCluster toolLabel={toolLabel ?? null} />
101	      <Divider />
102	      <SnapCluster snapModes={snapModes} onSnapToggle={onSnapToggle} />
103	      <Divider />
104	      <GridCluster gridOn={gridOn} onGridToggle={onGridToggle} />
105	      <Divider />
106	      <CoordCluster cursorMm={cursorMm ?? null} />
107	      <div className="ml-auto flex items-center gap-3">
108	        {conflictQueue ? (
109	          <>
110	            <ConflictSlot queue={conflictQueue} onClear={onClearConflict} />
111	            <Divider />
112	          </>
113	        ) : null}
114	        <UndoCluster depth={undoDepth ?? 0} onUndo={onUndo} onRedo={onRedo} />
115	        <Divider />
116	        <WsCluster state={wsState} />
117	        <Divider />
118	        <SaveCluster state={saveState} />
119	        <Divider />
120	        {/* Slot 5 — lens dropdown (CHR-V3-03 keystone, A8 antidote) */}
121	        <LensDropdown currentLens={lensMode} onLensChange={onLensChange ?? (() => {})} />
122	        {/* Slot 6 — drift badge; hidden when driftCount = 0 */}
123	        {driftCount > 0 ? (
124	          <>
125	            <Divider />
126	            <DriftBadge driftCount={driftCount} onClick={onDriftClick ?? (() => {})} />
127	          </>
128	        ) : null}
129	        {/* Slot 7 — CHR-V3-05 activity-stream entry */}
130	        <Divider />
131	        <ActivityEntry count={activityUnreadCount} onClick={onActivityClick} />
132	      </div>
133	    </div>
134	  );
135	}
136	
137	const statusStyle: CSSProperties = {
138	  height: 'var(--shell-statusbar-height)',
139	  minHeight: 'var(--shell-statusbar-height)',
140	};
141	
142	function Divider(): JSX.Element {
143	  return <span aria-hidden="true" className="inline-block h-3 w-px bg-border" />;
144	}
145	
146	function ConflictSlot({
147	  queue,
148	  onClear,
149	}: {
150	  queue: CollaborationConflictQueueV1;
151	  onClear?: () => void;
152	}): JSX.Element {
153	  const { t } = useTranslation();
154	  const [expanded, setExpanded] = useState(false);
155	  const retryLabels: Record<string, string> = {
156	    safe: t('statusbar.conflict.safeRetry'),
157	    blocked: t('statusbar.conflict.blocked'),
158	    requires_manual_edit: t('statusbar.conflict.manualEdit'),
159	  };
160	  const retryLabel = retryLabels[queue.retryAdvice] ?? queue.retryAdvice;
161	  return (
162	    <div className="relative flex items-center">
163	      <button
164	        type="button"
165	        aria-expanded={expanded}
166	        data-testid="conflict-pill"
167	        onClick={() => setExpanded((v) => !v)}
168	        className="flex items-center gap-1 rounded-sm px-1.5 py-0.5 font-medium text-amber-700 hover:bg-amber-50 dark:text-amber-300 dark:hover:bg-amber-950/30"
169	        title={t('statusbar.conflict.pill')}
170	      >
171	        <Icons.advisorWarning size={ICON_SIZE.chrome} aria-hidden="true" />
172	        <span>{t('statusbar.conflict.label')}</span>
173	        <span className="rounded bg-amber-100 px-1 py-px text-[9px] dark:bg-amber-900/40">
174	          {retryLabel}
175	        </span>
176	      </button>
177	      {expanded ? (
178	        <div
179	          data-testid="collaboration-conflict-queue-readout"
180	          role="dialog"
181	          aria-label={t('statusbar.conflict.dialogAriaLabel')}
182	          className="absolute bottom-full right-0 z-50 mb-1 w-96 rounded border border-amber-500/40 bg-surface px-3 py-2 text-[10px] shadow-elev-2"
183	        >
184	          <div className="flex items-center justify-between">
185	            <span className="font-semibold text-amber-800 dark:text-amber-300">
186	              {t('statusbar.conflict.heading')}
187	            </span>
188	            <button
189	              type="button"
190	              aria-label={t('statusbar.conflict.dismissAriaLabel')}
191	              data-testid="conflict-dismiss"
192	              onClick={() => {
193	                setExpanded(false);
194	                onClear?.();
195	              }}
196	              className="rounded-sm px-1 py-0.5 text-muted hover:bg-surface-strong"
197	            >
198	              ✕
199	            </button>
200	          </div>
201	          <p className="mt-1 text-foreground">{queue.inspectionReadout}</p>
202	          {queue.inspectionReadoutSecondary ? (
203	            <p className="mt-0.5 text-muted">{queue.inspectionReadoutSecondary}</p>
204	          ) : null}
205	          {queue.mergePreflightReadout ? (
206	            <p className="mt-0.5 text-muted">{queue.mergePreflightReadout}</p>
207	          ) : null}
208	          <ul className="mt-1 list-disc space-y-0.5 ps-4 text-muted">
209	            <li>
210	              Retry advice: <code className="font-mono text-[9px]">{queue.retryAdvice}</code>
211	              {queue.reason ? (
212	                <>
213	                  {' · '}reason <code className="font-mono text-[9px]">{queue.reason}</code>
214	                </>
215	              ) : null}
216	            </li>
217	            {queue.rows.length > 0 ? (
218	              <li>
219	                {queue.rows.length} blocking row(s) · rules{' '}
220	                <code className="text-[9px]">{queue.rows.map((r) => r.ruleId).join(', ')}</code>
221	              </li>
222	            ) : null}
223	            {queue.firstBlockingCommandStep1Based !== null ? (
224	              <li>
225	                Blocking command step {queue.firstBlockingCommandStep1Based}
226	                {queue.blockingCommandType ? ` (${queue.blockingCommandType})` : ''}
227	              </li>
228	            ) : null}
229	          </ul>
230	        </div>
231	      ) : null}
232	    </div>
233	  );
234	}
235	
236	function LevelCluster({
237	  level,
238	  levels,
239	  onLevelChange,
240	}: {
241	  level: { id: string; label: string };
242	  levels: { id: string; label: string }[];
243	  onLevelChange?: (id: string) => void;
244	}): JSX.Element {
245	  const { t } = useTranslation();
246	  const [open, setOpen] = useState(false);
247	  const popoverId = useId();
248	  const close = useCallback(() => setOpen(false), []);
249	  const handleKey = useCallback(
250	    (event: KeyboardEvent<HTMLDivElement>) => {
251	      if (event.key === 'PageDown' || event.key === 'PageUp') {
252	        if (!levels.length) return;
253	        const idx = levels.findIndex((l) => l.id === level.id);
254	        if (idx < 0) return;
255	        const delta = event.key === 'PageDown' ? 1 : -1;
256	        const next = levels[(idx + delta + levels.length) % levels.length];
257	        event.preventDefault();
258	        onLevelChange?.(next.id);
259	      } else if (event.key === 'Escape') {
260	        close();
261	      }
262	    },
263	    [close, level.id, levels, onLevelChange],
264	  );
265	
266	  return (
267	    <div onKeyDown={handleKey} className="relative flex items-center gap-1">
268	      <button
269	        type="button"
270	        aria-expanded={open}
271	        aria-controls={popoverId}
272	        aria-haspopup="menu"
273	        onClick={() => setOpen((v) => !v)}
274	        title={t('statusbar.levelTitle')}
275	        className="rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
276	      >
277	        {t('statusbar.levelLabel')}{' '}
278	        <span className="font-medium text-foreground">{level.label}</span>
279	        <Icons.disclosureOpen size={ICON_SIZE.chrome} aria-hidden="true" className="ml-1 inline" />
280	      </button>
281	      {open ? (
282	        <div
283	          id={popoverId}
284	          role="menu"
285	          aria-label={t('statusbar.levels')}
286	          className="absolute bottom-full left-0 z-50 mb-1 w-48 rounded-md border border-border bg-surface text-sm shadow-elev-2"
287	        >
288	          {levels.map((l) => (
289	            <button
290	              key={l.id}
291	              type="button"
292	              role="menuitem"
293	              onClick={() => {
294	                onLevelChange?.(l.id);
295	                close();
296	              }}
297	              className={[
298	                'flex w-full items-center justify-between px-3 py-1.5 text-left',
299	                l.id === level.id ? 'bg-accent-soft text-foreground' : 'hover:bg-surface-strong',
300	              ].join(' ')}
301	            >
302	              {l.label}
303	              {l.id === level.id ? (
304	                <span className="text-xs text-muted">{t('statusbar.levelActive')}</span>
305	              ) : null}
306	            </button>
307	          ))}
308	        </div>
309	      ) : null}
310	    </div>
311	  );
312	}
313	
314	function ToolCluster({ toolLabel }: { toolLabel: string | null }): JSX.Element {
315	  const { t } = useTranslation();
316	  return (
317	    <div aria-live="polite" className="flex items-center gap-1" title={t('statusbar.toolTitle')}>
318	      {t('statusbar.toolLabel')}{' '}
319	      <span className="font-medium text-foreground">{toolLabel ?? '—'}</span>
320	    </div>
321	  );
322	}
323	
324	function SnapCluster({
325	  snapModes,
326	  onSnapToggle,
327	}: {
328	  snapModes: { id: string; label: string; on: boolean }[];
329	  onSnapToggle?: (id: string) => void;
330	}): JSX.Element {
331	  const { t } = useTranslation();
332	  return (
333	    <div className="flex items-center gap-1" title={t('statusbar.snapTitle')}>
334	      <Icons.snap size={ICON_SIZE.chrome} aria-hidden="true" className="text-muted" />
335	      <span>{t('statusbar.snapLabel')}</span>
336	      <div role="group" aria-label={t('statusbar.snapModes')} className="flex items-center gap-1">
337	        {snapModes.length === 0 ? (
338	          <span className="text-muted">{t('statusbar.snapOff')}</span>
339	        ) : (
340	          snapModes.map((s) => (
341	            <button
342	              key={s.id}
343	              type="button"
344	              role="switch"
345	              aria-checked={s.on}
346	              onClick={() => onSnapToggle?.(s.id)}
347	              data-active={s.on ? 'true' : 'false'}
348	              className={[
349	                'rounded-sm px-1.5 py-0.5',
350	                s.on ? 'bg-accent-soft text-foreground' : 'text-muted hover:bg-surface-strong',
351	              ].join(' ')}
352	            >
353	              {s.label}
354	            </button>
355	          ))
356	        )}
357	      </div>
358	    </div>
359	  );
360	}
361	
362	function GridCluster({
363	  gridOn,
364	  onGridToggle,
365	}: {
366	  gridOn: boolean;
367	  onGridToggle?: () => void;
368	}): JSX.Element {
369	  const { t } = useTranslation();
370	  return (
371	    <button
372	      type="button"
373	      role="switch"
374	      aria-checked={gridOn}
375	      onClick={onGridToggle}
376	      title={t('statusbar.gridTitle')}
377	      className="flex items-center gap-1 rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
378	    >
379	      <Icons.grid size={ICON_SIZE.chrome} aria-hidden="true" />
380	      {t('statusbar.gridLabel')}{' '}
381	      <span className="font-medium">{gridOn ? t('statusbar.gridOn') : t('statusbar.gridOff')}</span>
382	    </button>
383	  );
384	}
385	
386	function CoordCluster({
387	  cursorMm,
388	}: {
389	  cursorMm: { xMm: number; yMm: number } | null;
390	}): JSX.Element {
391	  const { t } = useTranslation();
392	  return (
393	    <div aria-live="polite" aria-label={t('statusbar.coordsLabel')} className="font-mono text-xs">
394	      {cursorMm
395	        ? `X ${(cursorMm.xMm / 1000).toFixed(2)} m   Y ${(cursorMm.yMm / 1000).toFixed(2)} m`
396	        : 'X —   Y —'}
397	    </div>
398	  );
399	}
400	
401	function UndoCluster({
402	  depth,
403	  onUndo,
404	  onRedo,
405	}: {
406	  depth: number;
407	  onUndo?: () => void;
408	  onRedo?: () => void;
409	}): JSX.Element {
410	  const { t } = useTranslation();
411	  return (
412	    <div className="flex items-center gap-1">
413	      <button
414	        type="button"
415	        onClick={onUndo}
416	        title={t('statusbar.undoTitle')}
417	        aria-label={t('statusbar.undoLabel')}
418	        className="inline-flex h-5 w-5 items-center justify-center rounded-sm text-muted hover:bg-surface-strong"
419	      >
420	        <Icons.undo size={ICON_SIZE.chrome} aria-hidden="true" />
421	      </button>
422	      <span className="text-muted">{depth}</span>
423	      <button
424	        type="button"
425	        onClick={onRedo}
426	        title={t('statusbar.redoTitle')}
427	        aria-label={t('statusbar.redoLabel')}
428	        className="inline-flex h-5 w-5 items-center justify-center rounded-sm text-muted hover:bg-surface-strong"
429	      >
430	        <Icons.redo size={ICON_SIZE.chrome} aria-hidden="true" />
431	      </button>
432	    </div>
433	  );
434	}
435	
436	function WsCluster({ state }: { state: StatusWsState }): JSX.Element {
437	  const { t } = useTranslation();
438	  const wsColors: Record<StatusWsState, string> = {
439	    connected: 'var(--color-success)',
440	    reconnecting: 'var(--color-warning)',
441	    offline: 'var(--color-danger)',
442	  };
443	  const color = wsColors[state];
444	  const label = t(`statusbar.ws.${state}`);
445	  return (
446	    <div
447	      aria-live={state === 'offline' ? 'assertive' : 'polite'}
448	      title={t('statusbar.connection', { label })}
449	      className="flex items-center gap-1"
450	    >
451	      <Icons.online size={ICON_SIZE.chrome} aria-hidden="true" style={{ color }} />
452	      <span>{t('statusbar.wsLabel')}</span>
453	      <span style={{ color }}>{label}</span>
454	    </div>
455	  );
456	}
457	
458	function SaveCluster({ state }: { state: StatusSaveState }): JSX.Element {
459	  const { t } = useTranslation();
460	  const label = t(`statusbar.save.${state}`);
461	  return (
462	    <div
463	      aria-live={state === 'error' ? 'assertive' : 'polite'}
464	      title={t('statusbar.save.title', { state: label })}
465	      className="font-medium"
466	      style={{
467	        color:
468	          state === 'error'
469	            ? 'var(--color-danger)'
470	            : state === 'unsynced'
471	              ? 'var(--color-warning)'
472	              : 'var(--color-foreground)',
473	      }}
474	    >
475	      {label}
476	    </div>
477	  );
478	}
479	
480	function ActivityEntry({ count, onClick }: { count: number; onClick?: () => void }): JSX.Element {
481	  return (
482	    <button
483	      type="button"
484	      data-testid="status-bar-activity-entry"
485	      aria-label="Activity stream"
486	      title="Cmd+H"
487	      onClick={onClick}
488	      className="status-bar__slot status-bar__activity-entry relative flex items-center gap-1 rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
489	    >
490	      <Icons.collaborators size={ICON_SIZE.chrome} aria-hidden="true" />
491	      {count > 0 && (
492	        <span
493	          data-testid="status-bar-activity-badge"
494	          style={{
495	            position: 'absolute',
496	            top: 0,
497	            right: 0,
498	            minWidth: 14,
499	            height: 14,
500	            borderRadius: 7,
501	            background: 'var(--color-accent)',
502	            color: 'var(--color-surface)',
503	            fontSize: 'var(--text-3xs)',
504	            fontWeight: 700,
505	            display: 'flex',
506	            alignItems: 'center',
507	            justifyContent: 'center',
508	            padding: '0 3px',
509	            lineHeight: 1,
510	          }}
511	        >
512	          {count}
513	        </span>
514	      )}
515	    </button>
516	  );
517	}
518	
519	export type { ReactNode };
